"""Platform-dependent objects"""

import sys

if sys.flags.optimize == 2:
    raise RuntimeError("Cerberus can't be run with Python's optimization level 2.")


_int_types = (int,)
_str_type = str


import importlib.metadata as importlib_metadata
from collections.abc import (
    Callable,
    Container,
    Hashable,
    Iterable,
    Mapping,
    MutableMapping,
    Sequence,
    Set,
    Sized,
)

__all__ = (
    "_int_types",
    "_str_type",
    "importlib_metadata",
    Callable.__name__,
    Container.__name__,
    Hashable.__name__,
    Iterable.__name__,
    Mapping.__name__,
    MutableMapping.__name__,
    Sequence.__name__,
    Set.__name__,
    Sized.__name__,
)
